const endereco = ($("Webhook").item.json.body.cliente_endereco || "").trim();

const m = endereco.match(/\b([A-Z]{2})$/i);

if (!m) {
  return [{ json: { cidade_uf: null } }];
}

const uf = m[1].toUpperCase();
const texto = endereco.replace(/\b[A-Z]{2}$/i, "").trim();

const municipios = $("Lista Municipios")
  .all()
  .map(i => i.json.nome)
  .sort((a, b) => b.length - a.length);

const normalizar = (str) =>
  str
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toUpperCase();

const textoNormalizado = normalizar(texto);

const cidade = municipios.find(nome =>
  textoNormalizado.endsWith(normalizar(nome))
);

return [
  {
    json: {
      cidade_uf: cidade ? `${cidade}/${uf}` : null
    }
  }
];

// $input agora é a resposta do HTTP Request, porque é ele quem alimenta este node
const catalogoResponse = $input.item.json;
const catalogo = Array.isArray(catalogoResponse)
  ? catalogoResponse[0].opcoes
  : catalogoResponse.opcoes;

// O documento não vem mais do $input — precisa buscar explicitamente
// do node anterior ao HTTP Request na mesma iteração do loop
const documento = $('Verifica se eh termo_autorizacao_inss').item.json;

const TIPO_ALVO = 'termo_autorizacao_inss'; // confirme esse valor com o SELECT pendente

if (documento.tipo_id !== TIPO_ALVO) {
  return { json: documento };
}

let selecionadas = documento.opcoes_selecionadas;
if (typeof selecionadas === 'string') {
  selecionadas = JSON.parse(selecionadas);
}
selecionadas = selecionadas || [];
const selecionadasSet = new Set(selecionadas);

const checkboxRequests = catalogo.map(opcao => {
  const marcado = opcao.grupoPai
    ? selecionadasSet.has(opcao.id) && selecionadasSet.has(opcao.grupoPai)
    : selecionadasSet.has(opcao.id);

  return {
    replaceAllText: {
      containsText: { text: opcao.placeholder, matchCase: true },
      replaceText: marcado ? '(X)' : '(   )'
    }
  };
});

return {
  json: {
    ...documento,
    checkbox_requests: checkboxRequests
  }
};

