  { id: 'pensao_zika', grupoPai: null, placeholder: '{{CB_PENSAO_ZIKA}}' },
  { id: 'auxilio_reclusao', grupoPai: null, placeholder: '{{CB_AUXILIO_RECLUSAO}}' },
  { id: 'auxilio_reclusao_urbano', grupoPai: 'auxilio_reclusao', placeholder: '{{CB_AUXILIO_RECLUSAO_URBANO}}' },
  { id: 'auxilio_reclusao_rural', grupoPai: 'auxilio_reclusao', placeholder: '{{CB_AUXILIO_RECLUSAO_RURAL}}' },
  { id: 'salario_maternidade', grupoPai: null, placeholder: '{{CB_SALARIO_MATERNIDADE}}' },
  { id: 'salario_maternidade_urbano', grupoPai: 'salario_maternidade', placeholder: '{{CB_SALARIO_MATERNIDADE_URBANO}}' },
  { id: 'salario_maternidade_rural', grupoPai: 'salario_maternidade', placeholder: '{{CB_SALARIO_MATERNIDADE_RURAL}}' },
  { id: 'seguro_desemprego_pescador', grupoPai: null, placeholder: '{{CB_SEGURO_DESEMPREGO_PESCADOR}}' },
  { id: 'ctc', grupoPai: null, placeholder: '{{CB_CTC}}' },
  { id: 'copia_processo', grupoPai: null, placeholder: '{{CB_COPIA_PROCESSO}}' },
  { id: 'revisao_beneficios', grupoPai: null, placeholder: '{{CB_REVISAO_BENEFICIOS}}' },
  { id: 'recurso', grupoPai: null, placeholder: '{{CB_RECURSO}}' },
  { id: 'atualizacoes_manutencao', grupoPai: null, placeholder: '{{CB_ATUALIZACOES_MANUTENCAO}}' },
  { id: 'orientacoes_digitais', grupoPai: null, placeholder: '{{CB_ORIENTACOES_DIGITAIS}}' },
];

// 1) Dados do cliente — sempre presentes, em qualquer documento do kit
const substituicoesClienteData = [
  { placeholder: '{{CLIENTE_NOME_COMPLETO}}', valor: cliente.cliente_nome_completo },
  { placeholder: '{{CLIENTE_NACIONALIDADE}}', valor: cliente.cliente_nacionalidade },
  { placeholder: '{{CLIENTE_ESTADO_CIVIL}}', valor: cliente.cliente_estado_civil },
  { placeholder: '{{CLIENTE_PROFISSAO}}', valor: cliente.cliente_profissao },
  { placeholder: '{{CLIENTE_CPF}}', valor: cliente.cliente_cpf },
  { placeholder: '{{CLIENTE_ENDERECO}}', valor: cliente.cliente_endereco },
  { placeholder: '{{CLIENTE_EMAIL}}', valor: cliente.cliente_email },
  { placeholder: '{{CIDADE_UF}}', valor: cliente.cidade_uf },
];

// 2) Checkboxes — só existem no Termo de Representação/Acesso INSS
let substituicoesCheckbox = [];
if (documento.tipo_id === 'termo_ciencia') {
  let selecionadas = documento.opcoes_selecionadas;
  if (typeof selecionadas === 'string') selecionadas = JSON.parse(selecionadas);
  selecionadas = selecionadas || [];
  const selecionadasSet = new Set(selecionadas);

  substituicoesCheckbox = CATALOGO_TERMO_INSS.map(opcao => {
    const marcado = opcao.grupoPai
      ? selecionadasSet.has(opcao.id) && selecionadasSet.has(opcao.grupoPai)
      : selecionadasSet.has(opcao.id);
    return { placeholder: opcao.placeholder, valor: marcado ? '(X)' : '(   )' };
  });
}

// 3) Monta o array de requests no formato exigido pela Google Docs API,
//    descartando qualquer placeholder sem valor (evita request malformado)
const requests = [...substituicoesClienteData, ...substituicoesCheckbox]
  .filter(item => item.valor !== undefined && item.valor !== null)
  .map(item => ({
    replaceAllText: {
      containsText: { text: item.placeholder, matchCase: true },
      replaceText: String(item.valor)
    }
  }));

return {
  json: {
    ...documento,
    documentId,
    requests
  }
};

